SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Monotherapy/combination" = 'Combination' AND "Type of therapy" = 'immunotherapy and chemotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder' AND "Class of ICI" = 'PD1' AND "Is PD-L1 positivity inclusion criteria" = 'No';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Small Cell Lung' AND "Monotherapy/combination" = 'Combination' AND "Type of combination" = 'immunotherapy plus immunotherapy plus chemotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Class of ICI", "Cancer type", "Trial phase", "Included in MA"
FROM clinical_trials
WHERE "Cancer type" = 'Small Cell Lung' AND "Name of ICI" LIKE '%PD-L1%' AND "Name of ICI" LIKE '%CTLA-4%' AND "Included in MA" = 'Yes';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Class of ICI" = 'PD1' AND "Is PD-L1 positivity inclusion criteria" = 'No';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Class of ICI" = 'PD1' AND "Is PD-L1 positivity inclusion criteria" = 'No';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Hodgkin Lymphoma' AND "Class of ICI" = 'PD1' AND "Is PD-L1 positivity inclusion criteria" = 'No';
